// This function gets bet results from the external API.
// It takes gameId and betId as arguments and returns the result index.

// Get the gameId and betId from args
// args[0] = gameId, args[1] = betId
const gameId = args[0];
const betId = args[1];

// Construct the API URL
const apiUrl = `https://oracle-silk.vercel.app/api/results/${betId}`;

// Execute the API request (Promise)
const apiResponse = await Functions.makeHttpRequest({
  url: apiUrl,
});

if (apiResponse.error) {
  console.error(apiResponse.error);
  throw Error("Request failed");
}

const { data } = apiResponse;

console.log("API response data:", JSON.stringify(data, null, 2));
console.log("API response data type:", typeof data);
console.log(
  "API response data keys:",
  data ? Object.keys(data) : "data is null/undefined"
);

// Parse the response to get the result
// The API returns: { gameResult: { verdict: "{\"outcome\":\"PLAYER1\"}" } }
// The verdict is a JSON string that needs to be parsed first

let resultString;

if (data && data.gameResult) {
  const gameResult = data.gameResult;

  // Check if verdict exists
  if (gameResult.verdict) {
    try {
      // Parse the verdict JSON string if it's a string
      let verdict;
      if (typeof gameResult.verdict === "string") {
        verdict = JSON.parse(gameResult.verdict);
        console.log(
          "Parsed verdict JSON string:",
          JSON.stringify(verdict, null, 2)
        );
      } else {
        verdict = gameResult.verdict;
        console.log(
          "Verdict is already an object:",
          JSON.stringify(verdict, null, 2)
        );
      }

      // Extract outcome from parsed verdict
      if (verdict && verdict.outcome) {
        resultString = verdict.outcome;
        console.log("Found outcome in verdict.outcome:", resultString);
      } else {
        console.error("Verdict parsed but no outcome field found");
        console.error("Verdict structure:", JSON.stringify(verdict, null, 2));
      }
    } catch (parseError) {
      console.error("Error parsing verdict JSON:", parseError);
      console.error("Verdict value:", gameResult.verdict);
      // If parsing fails, try to use verdict as-is if it's already a string
      if (typeof gameResult.verdict === "string") {
        resultString = gameResult.verdict;
        console.log("Using verdict as string (parsing failed):", resultString);
      }
    }
  }

  // Fallback: try direct outcome field in gameResult
  if (!resultString && gameResult.outcome) {
    resultString = gameResult.outcome;
    console.log("Found outcome in gameResult.outcome:", resultString);
  }
}

// Additional fallbacks
if (!resultString && data && data.result) {
  resultString = data.result;
  console.log("Found result in data.result:", resultString);
} else if (!resultString && data && data.resultIndex !== undefined) {
  resultString = String(data.resultIndex);
  console.log("Found resultIndex:", resultString);
} else if (!resultString && data && data.verdict) {
  // If verdict is at root level
  if (typeof data.verdict === "string") {
    try {
      const verdict = JSON.parse(data.verdict);
      if (verdict && verdict.outcome) {
        resultString = verdict.outcome;
        console.log("Found outcome in root level verdict:", resultString);
      }
    } catch (e) {
      resultString = data.verdict;
      console.log("Using root level verdict as string:", resultString);
    }
  } else if (data.verdict.outcome) {
    resultString = data.verdict.outcome;
    console.log("Found outcome in root level verdict.outcome:", resultString);
  }
}

// If still no result found, throw an error
if (!resultString) {
  console.error("Could not find result in API response");
  console.error("Full data structure:", JSON.stringify(data, null, 2));
  throw Error(
    "Result not found in API response. Check logs for response structure."
  );
}

console.log("Parsed result:", resultString);

// Return the result as an encoded string
// The outcome value is a bytes32 option identifier (e.g., "PLAYER1", "PLAYER2", etc.)
// This will be handled by the contract logic
return Functions.encodeString(resultString);
